<template>
   <div>
      <!-- 面包屑 -->
      <el-breadcrumb separator-class="el-icon-arrow-right">
         <el-breadcrumb-item :to="{ path: '/' }">首页</el-breadcrumb-item>
         <el-breadcrumb-item>商品管理</el-breadcrumb-item>
         <el-breadcrumb-item>商品列表</el-breadcrumb-item>
      </el-breadcrumb>

      <!-- 卡片 -->
      <el-card class="box-card">
         <!-- 扇框布局 -->
         <el-row :gutter="12">
            <!-- 搜索框 -->
            <el-col :span="8">
               <div class="grid-content bg-purple">
                  <el-input placeholder="请输入内容" @clear="ajax" :clearable="true" v-model="shu.query"
                     class="input-with-select">
                     <el-button slot="append" icon="el-icon-search" @click="ajax()"></el-button>
                  </el-input>
               </div>
            </el-col>
            <el-col :span="4">
               <div class="grid-content bg-purple">
                  <el-button type="primary" @click="tianjia = true">添加商品</el-button>
               </div>
            </el-col>
         </el-row>
         <!-- 表格 -->
         <template>
            <el-table :data="tableData" border style="width: 100%">
               <el-table-column type="index" label="#">
               </el-table-column>
               <el-table-column prop="goods_name" label="商品名称" width="680">
               </el-table-column>
               <el-table-column prop="goods_price" label="商品价格">
               </el-table-column>
               <el-table-column prop="goods_weight" label="商品重量">
               </el-table-column>
               <el-table-column prop="upd_time" label="创建时间">
                  <template slot-scope="scope">
                     {{scope.row.upd_time|timefn}}
                  </template>
               </el-table-column>

               <el-table-column>
                  <!-- 具名插槽   -->
                  <template slot-scope="scope">
                     <!-- {{scope.row}} -->
                     <el-tooltip content="编辑" placement="top">
                        <el-button type="primary" @click="edit(scope.row)" icon="el-icon-edit" circle></el-button>
                     </el-tooltip>

                     <el-tooltip content="删除" placement="top">
                        <el-button type="danger"  @click="open(scope.row.goods_id)" icon="el-icon-delete" circle></el-button>
                     </el-tooltip>

                  </template>
               </el-table-column>
            </el-table>
         </template>
         <!-- 分页 -->
         <el-pagination @size-change="handleSizeChange" @current-change="handleCurrentChange"
            :page-sizes="[6, 20, 30, 40]" :page-size="shu.pagesize" layout="total, sizes, prev, pager, next, jumper"
            :total="total">
         </el-pagination>

         <!-- 编辑弹出框 -->
         <el-dialog
            title="修改商品"
            :visible.sync="dialogVisible"
            width="30%">
            <!-- <span>这是一段信息</span> -->
            <!-- from表单 -->
            <el-form :model="ruleForm"  ref="ruleForm" label-width="100px" class="demo-ruleForm">
               <el-form-item label="商品名称" prop="name">
                 <el-input v-model="ruleForm.goods_name"></el-input>
               </el-form-item>
               <el-form-item label="商品价格" prop="name">
                  <el-input v-model="ruleForm.goods_price"></el-input>
                </el-form-item>
                <el-form-item label="商品数量" prop="name">
                  <el-input v-model="ruleForm.goods_number"></el-input>
                </el-form-item>
                <el-form-item label="商品重量" prop="name">
                  <el-input v-model="ruleForm.goods_weight"></el-input>
                </el-form-item>

            </el-form>
            <span slot="footer" class="dialog-footer">
               <el-button @click="dialogVisible = false">取 消</el-button>
               <el-button type="primary" @click="queEdit()">确 定</el-button>
            </span>
         </el-dialog>

         <!-- 添加弹出框 -->
         <el-dialog
            title="添加商品"
            :visible.sync="tianjia"
            width="30%">
            <!-- <span>这是一段信息</span> -->
             <!-- from表单 -->
             <el-form :model="add"  ref="ruleForm" label-width="100px" class="demo-ruleForm">
               <el-form-item label="商品名称" prop="name">
                 <el-input v-model="add.goods_name"></el-input>
               </el-form-item>
               <el-form-item label="分类列表" prop="name">
                  <el-input v-model="add.goods_cat"></el-input>
                </el-form-item>
               <el-form-item label="商品价格" prop="name">
                  <el-input v-model="add.goods_price"></el-input>
                </el-form-item>
                <el-form-item label="商品数量" prop="name">
                  <el-input v-model="add.goods_number"></el-input>
                </el-form-item>
                <el-form-item label="商品重量" prop="name">
                  <el-input v-model="add.goods_weight"></el-input>
                </el-form-item>

            </el-form>
            <span slot="footer" class="dialog-footer">
               <el-button @click="dialogVisible = false">取 消</el-button>
               <el-button type="primary" @click="quetian()">确 定</el-button>
            </span>
         </el-dialog>


      </el-card>
   </div>
</template>

<script>
   export default {
      data() {
         return {
            shu: {
               query: '',
               pagenum: 1,
               pagesize: 6
            },
            // 编辑
            ruleForm:{
               id:null,
               goods_name:'',
               goods_cat:'',
               goods_price:'',
               goods_number:'',
               goods_weight:'',
               goods_introduce:'',
               pics:'',
               attrs:''
            },
            // 添加商品
            add:{
               id:null,
               goods_name:'',
               goods_price:'',
               goods_number:'',
               goods_weight:'',
               goods_introduce:'',
               pics:'',
               attrs:''
            },
            tableData: [],
            total: 0,
            dialogVisible: false,
            tianjia:false
         };
      },
      created() {

      },
      mounted() {
         this.ajax()
      },
      methods: {
         async ajax() {
            let { data } = await this.$http.get(`/goods?query=${this.shu.query}&pagenum=${this.shu.pagenum}&pagesize=${this.shu.pagesize}`)
            this.total = data.data.total
            this.tableData = data.data.goods
            console.log(this.tableData)

         },
         handleSizeChange(val) {
            // console.log(`每页 ${val} 条`);
            this.shu.pagesize = val
            this.ajax()
         },
         handleCurrentChange(val) {
            // console.log(`当前页: ${val}`);
            this.shu.pagenum = val
            this.ajax()
         },
         open(id) {
            console.log(id)
            this.$confirm('此操作将永久删除该商品, 是否继续?', '提示', {
               confirmButtonText: '确定',
               cancelButtonText: '取消',
               type: 'warning'
            }).then(() => {
               this.$message({
                  type: 'success',
                  message: '删除成功!'
               });
               this.$http.delete('/goods/'+id).then(res=>{
                  console.log(res)
                  if(res.data.meta.msg=='删除成功'){
                     this.ajax()
                  }
               })
            })
         },
         // 点击编辑的时候。出来编辑框
         edit(obj){
            this.dialogVisible=true
            console.log(obj)
            this.ruleForm=obj
         },
         // 确定编辑的时候
         queEdit(){
            this.$http.put('/goods/'+this.ruleForm.goods_id,{
               // id:this.ruleForm.goods_id,
               goods_name:this.ruleForm.goods_id,
               goods_price:this.ruleForm.goods_price,
               goods_number:this.ruleForm.goods_number,
               goods_weight:this.ruleForm.goods_weight,

            }).then(res=>{
               console.log(res)
            })
         },
         // 确定添加的时候
         quetian(){
            this.$http.post('/goods',{
               goods_name:this.add.goods_name,
               goods_cat:this.add.goods_cat,
               goods_price:this.add.goods_price,
               goods_number:this.add.goods_number,
               goods_weight:this.add.goods_weight,
               goods_introduce:this.add.goods_introduce,
               pics:this.add.goods_pics,
               attrs:this.add.goods_attrs,
            }).then(res=>{
               console.log(res)
            })
         }
      }
   };
</script>

<style scoped>
   .box-card {
      margin-top: 10px;
   }
</style>